<script setup lang="ts">
import { computed, onMounted, reactive } from 'vue'
import { useBillingStore } from '@/stores'
import { useRoute, useRouter } from 'vue-router'
import type { OrderInfo, PaymentTypeInfo } from '@/types'
import { PaymentType, paymentTypeMap } from '@/plugins/payment'

const props = defineProps<{
  paymentType: string,
  paymentHash: string,
  orderInfos: OrderInfo[],
  paymentTotalAmount: number
}>()

const router = useRouter()
const route = useRoute()
const billingStore = useBillingStore()

billingStore.updatePaymentHash(props.paymentHash)
billingStore.updateOrderInfos(props.orderInfos)
billingStore.updatePaymentTotalAmount(props.paymentTotalAmount)

const state = reactive({
  paymentTypes: [],
  activeType: computed(() => billingStore.activeType),
  disablePayment: false,
  showPayment: computed(() => billingStore.showPayment),
  defaultOpenPaymentType: computed(() => billingStore.defaultOpenPaymentType),
})

const resetResult = () => {
  billingStore.updateResult({
    buId: null,
    paymentType: null,
    paymentStatus: 0,
    virtualAccount: null,
    approveCode: null,
    customerTransDate: null,
    orderIdList: null,
    saveCardStatus: 0,
    installmentTerm: 0
  })
}

const showPaymentBox = (paymentTypeInfo: PaymentTypeInfo) => {
  if (!state.disablePayment) {
    resetResult()
    // 點擊付款按鈕時，判斷是否開啟或關閉付款區塊
    if (state.activeType !== paymentTypeInfo.name) {
      billingStore.updateActiveType(paymentTypeInfo.name)
      if (route.name !== 'Home') {
        router.push({
          name: 'Home'
        })
      }
      router.push({
        name: paymentTypeInfo.name
      })
    } else {
      billingStore.updateActiveType(null)
    }
  }
}

/**
 * 自動打開 BU 指定的付款方式
 */
const showDefaultPaymentBox = (): void => {
  const paymentType = state.paymentTypes.find(({ type }) => type !== '' && type === state.defaultOpenPaymentType)
  if (paymentType) {
    showPaymentBox(paymentType)
  }
}

/**
 * 按下「 確定付款 」時, disable 所有付款按鈕
 */
const updateDisablePayment = (isDisable: boolean) => {
  state.disablePayment = isDisable
}

/**
 * 隱藏指定的付款按鈕 (目前提供分期付款遇到特定的 errCode 時, 隱藏分期按鈕)
 */
const hiddenPaymentButton = (paymentTypeInfo: PaymentTypeInfo) => {
  state.paymentTypes = state.paymentTypes.filter(paymentType => paymentType.name !== paymentTypeInfo.name)
}

onMounted(() => {
  if (props.paymentType) {
    const saveCardInfo = billingStore.saveCardInfo
    const isSubscriptionOrder = (saveCardInfo && saveCardInfo.orderSaveCardType === 2) as boolean
    const existSaveCardInfo = !!(saveCardInfo && saveCardInfo.pan && saveCardInfo.expDate && saveCardInfo.saveCardInfoStatus > 0)
    const orderPaymentTypes = billingStore.orderPaymentType.split('|')
    const installmentInfos = billingStore.installmentInfos

    state.paymentTypes = paymentTypeMap.filter(paymentType => {
      // 如果是訂閱制綁卡且卡片有效，則只顯示信用卡付款方式
      if (isSubscriptionOrder && existSaveCardInfo) {
        return paymentType.name === PaymentType.CreditCard.name
      }

      // 當訂單的付款方式有傳 1 (信用卡) 及 /order/mapping 有回傳可用的分期時, 才顯示分期按鈕
      if (paymentType.name === PaymentType.Installment.name) {
        return orderPaymentTypes.includes(paymentType.type.toString()) && installmentInfos && installmentInfos.length > 0
      }

      // 其餘依照訂單的 paymentType 來過濾付款方式
      return orderPaymentTypes.includes(paymentType.type.toString())
    })
  }

  showDefaultPaymentBox()
})
</script>

<template>
  <div class="section">
    <div ref="payment-container" class="payment-container">
      <div class="payment-button-group">
        <div v-for="(paymentObject, index) in state.paymentTypes" v-show="state.showPayment" :key="index" style="position:relative;">
          <div v-show="state.activeType === paymentObject.name" class="corner"></div>
          <div v-show="state.activeType === paymentObject.name" class="check"></div>
          <input
            :ref="`payment-button${index}`" type="button" class="payment-button"
            :class="{ active: state.activeType === paymentObject.name }"
            :style="{ backgroundImage: `url(${paymentObject.url})` }" :disabled="state.disablePayment" @click="showPaymentBox(paymentObject)"
          />
        </div>
      </div>
      <router-view v-slot="{ Component }">
        <transition name="bounce">
          <Component :is="Component" v-show="state.activeType" @update-disable-payment="updateDisablePayment" @hidden-payment-button="hiddenPaymentButton" />
        </transition>
      </router-view>
    </div>
  </div>
</template>
