<script setup lang="ts">
import visa from '@/assets/images/btn_credit_visa_off.svg'
import master from '@/assets/images/btn_credit_master_off.svg'
import jcb from '@/assets/images/btn_credit_jcb_off.svg'
import ConfirmButton from '@/components/ConfirmButton.vue'
import { computed, getCurrentInstance, onMounted, reactive } from 'vue'
import { useRouter } from 'vue-router'
import { useBillingStore } from '@/stores'
import type { FailedResult, InstallmentInfo, OrderInfo, Result } from '@/types'
import { useField, useForm } from 'vee-validate'
import { goToFirstError } from '@/plugins/validators'
import { PaymentType } from '@/plugins/payment'
import { generateHmacSignature } from '@/plugins/signature'

const emit = defineEmits(['update-disable-payment', 'hidden-payment-button'])
const router = useRouter()
const billingStore = useBillingStore()
const currentInstance = getCurrentInstance()
const api104 = currentInstance.proxy.$api104

const { handleSubmit } = useForm()
const year = new Date().getFullYear() % 100

// 綁定表單欄位資料,驗證規則及預設值
const validCardNumber = useField('cardNumber', 'required|digitNumber:信用卡號 格式錯誤', { initialValue: '' })
const validExpMonth = useField('expMonth', 'required|month', { initialValue: '' })
const validExpYear = useField('expYear', 'required|year', { initialValue: '' })
const validSecurityCode = useField('securityCode', 'required|securityCode', { initialValue: '' })
const validInstallmentTerm = useField('installmentTerm', 'required', { initialValue: billingStore.installmentInfos[0].value })

// Component 資料狀態
const state = reactive({
  isLoading: false,
  cardTypes: [{
    name: 'visa',
    icon: computed(() => getIconUrl('/img/btn_credit_visa_off.svg', visa)),
    isActive: false
  },
  {
    name: 'mastercard',
    icon: computed(() => getIconUrl('/img/btn_credit_master_off.svg', master)),
    isActive: false
  },
  {
    name: 'jcb',
    icon: computed(() => getIconUrl('/img/btn_credit_jcb_off.svg', jcb)),
    isActive: false
  }],
  creditCardInfo: computed(() => ({
    pan: validCardNumber.value.value,
    cvv2: validSecurityCode.value.value,
    expDate: '20'.concat(validExpYear.value.value).concat(validExpMonth.value.value),
    installmentTerm: validInstallmentTerm.value.value
  })),
  cleaveOptions: {
    creditCard: true,
    delimiter: ' ',
    onCreditCardTypeChanged: type => {
      state.cardTypes.forEach(cardType => {
        cardType.isActive = cardType.name === type
      })
    }
  },
  expMonthArray: Array.from({ length: 12 }, (_, i) => (i + 1).toString().padStart(2, '0')),
  expYearArray: Array.from({ length: 10 }, (_, i) => ((year + i) % 100).toString()),
  installmentInfos: [] as InstallmentInfo[]
})

const getIconUrl = (iconPath: string, fallback: string) => {
  return import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat(iconPath) : fallback
}

// 呼叫後端刷卡分期 API
const creditInstallmentAuth = async () => {
  const hmacSignature = await generateHmacSignature(`${state.creditCardInfo.pan}${state.creditCardInfo.expDate}${state.creditCardInfo.cvv2}`, billingStore.paymentHash)

  return await api104.post(
    '/webapis/pay/credit/installment',
    state.creditCardInfo,
    {
      headers: {
        '104-Pay-Hmac': billingStore.paymentHash,
        'Id-Token-Hash': billingStore.idTokenHash,
        'Billing-Authorization': hmacSignature,
      }
    }
  )
}

// 轉換 API 回傳的資料為成功付款結果
const getSuccessResult = (orderInfos: OrderInfo[] = [], response: any = {}) => {
  const data = response?.data?.data || {}
  return {
    buId: orderInfos[0]?.buId || null,
    paymentType: '1',
    paymentStatus: 1,
    virtualAccount: null,
    approveCode: data.authCode || '',
    customerTransDate: data.transDateTime || null,
    orderIdList: orderInfos.map(value => value.orderId),
    saveCardStatus: 0,
    installmentTerm: data.installmentTerm
  } as Result
}

// 轉換 API 回傳的資料為失敗付款結果
const getFailedResult = (orderInfos: OrderInfo[] = [], response: any = {}) => {
  const data = response?.data?.data || {}
  return {
    buId: orderInfos[0]?.buId || null,
    paymentType: '1',
    paymentStatus: 0,
    customerTransDate: data.transDateTime || null,
    errCode: data.errCode || '',
    errDesc: data.errDesc || response?.data?.message || '',
    gatewayName: data.gatewayName || '',
    orderIdList: orderInfos.map(value => value.orderId),
    saveCardStatus: 0
  } as FailedResult
}

// 提供 handleSubmit 處理驗證失敗後的邏輯, Focus 到第一個錯誤欄位
const errorCallBack = ({ results }) => goToFirstError(currentInstance.refs.observer as Element, results)

// 確認付款
const confirm = handleSubmit(async () => {
  // disable 各付款方式的按鈕
  emit('update-disable-payment', true)
  state.isLoading = true

  // 呼叫後端刷卡分期 API
  const response = await creditInstallmentAuth()
  state.isLoading = false

  // 是否付款成功
  if (response && response.data && response.data.data && response.data.data.paymentStatus) {
    // 付款成功後, 將各付款方式的按鈕隱藏
    billingStore.updateShowPayment(false)

    const result = getSuccessResult(billingStore.orderInfos, response)
    if (window.payComplete) {
      window.payComplete(result)
    }

    await router.push({
      name: 'CreditCardSuccess',
      params: {
        paymentType: '1',
        saveCardStatus: 0
      }
    })
  } else {
    // 付款失敗後, enable 各付款方式的按鈕
    emit('update-disable-payment', false)

    // 超過分期授權額度 或 傳入的期數參數與設定檔不符, 則隱藏分期按鈕
    if (response && response.data && response.data.data && response.data.data.errStatus === 498) {
      emit('hidden-payment-button', PaymentType.Installment)
    }

    const result = getFailedResult(billingStore.orderInfos, response)
    if (window.payFailed) {
      window.payFailed(result)
    }

    // 儲存異常訊息, 提供 CreditCardFail Component 顯示
    billingStore.updateApiResponse(result.errCode, result.errDesc)
    await router.push({
      name: 'CreditCardFail'
    })
  }
}, errorCallBack)

// 取得當下選擇期數的支援銀行描述
const getInstallmentDescription = () => {
  return state.installmentInfos.filter(installment => installment.value === state.creditCardInfo.installmentTerm)[0]?.description || ''
}

onMounted(() => {
  state.installmentInfos = billingStore.installmentInfos
})
</script>

<template>
  <div ref="observer" class="payment-method" style="position:relative">
    <loading-component v-if="state.isLoading" loader="spinner" :active="true" :is-full-page="false" />

    <div class="payment-method-row">
      <!-- 信用卡別區塊 -->
      <div class="credit-card-row">
        <label class="payment-method-word">信用卡別</label>
        <div
          v-for="cardType in state.cardTypes"
          :key="cardType.name"
          :style="{ backgroundImage: `url(${cardType.icon})` }"
          :class="['card-type', { active: cardType.isActive}]"
        ></div>
      </div>

      <!-- 信用卡號區塊 -->
      <div class="credit-card-row no-margin">
        <label class="payment-method-word">信用卡號</label>
        <div class="credit-card-column">
          <div class="cleave-wrapper">
            <cleave
              v-model="validCardNumber.value.value"
              inputmode="numeric"
              name="cardNumber"
              :options="state.cleaveOptions"
              class="credit-card-input"
              :class="{ 'input-error': validCardNumber.errorMessage.value }"
              placeholder="0000 0000 0000 0000"
              @blur="validCardNumber.validate()"
            ></cleave>
          </div>
          <div v-if="validCardNumber.errorMessage.value" class="error">{{ validCardNumber.errorMessage.value }}</div>
          <div v-else class="reserve"></div>
        </div>
      </div>

      <!-- 有效期限區塊 -->
      <div class="credit-card-row no-margin">
        <label class="payment-method-word">有效期限</label>
        <div class="credit-card-column">
          <select
            v-model="validExpMonth.value.value"
            name="expMonth"
            class="credit-card-input input-m-size"
            :class="{ 'input-error': validExpMonth.errorMessage.value }"
            autocomplete="off"
            @blur="validExpMonth.validate()"
          >
            <option v-for="value in state.expMonthArray" :key="`month${value}`" :value="value">{{ value }}</option>
          </select>
          <div v-if="validExpMonth.errorMessage.value" class="error error-m-size">{{ validExpMonth.errorMessage.value }}</div>
          <div v-else class="reserve"></div>
        </div>
        <label class="payment-method-word word-m-size" style="width: 60px">月 / 20</label>
        <div class="credit-card-column">
          <select
            v-model="validExpYear.value.value"
            name="expYear"
            class="credit-card-input input-m-size"
            :class="{ 'input-error': validExpYear.errorMessage.value }"
            autocomplete="off"
            @blur="validExpYear.validate()"
          >
            <option v-for="value in state.expYearArray" :key="`year${value}`" :value="value">{{ value }}</option>
          </select>
          <div v-if="validExpYear.errorMessage.value" class="error error-m-size">{{ validExpYear.errorMessage.value }}</div>
          <div v-else class="reserve"></div>
        </div>
        <label class="payment-method-word word-s-size" style="width: 30px">年</label>
      </div>

      <!-- 安全碼區塊 -->
      <div class="credit-card-row no-margin">
        <label class="payment-method-word">安全碼</label>
        <div class="credit-card-column">
          <input
            v-model="validSecurityCode.value.value"
            inputmode="numeric"
            type="text"
            name="securityCode"
            :class="{ 'input-error': validSecurityCode.errorMessage.value }"
            class="credit-card-input input-m-size"
            placeholder="000"
            maxlength="3"
            autocomplete="off"
            @blur="validSecurityCode.validate()"
          >
          <div v-if="validSecurityCode.errorMessage.value" class="error">{{ validSecurityCode.errorMessage.value }}</div>
          <div v-else class="reserve"></div>
        </div>
      </div>

      <!-- 分期區塊 -->
      <div class="credit-card-row no-margin">
        <label class="payment-method-word">分期期數</label>
        <div class="credit-card-column">
          <div class="radio-group">
            <div v-for="(installment, index) in state.installmentInfos" :key="`radio-installment-${index}`" class="radio-item">
              <input
                :id="`radio-installment-${index}`"
                v-model="validInstallmentTerm.value.value"
                type="radio"
                name="installmentTerm"
                :value="installment.value"
              >
              <label :for="`radio-installment-${index}`" class="payment-method-word word-m-size">{{ installment.text }}</label>
            </div>
          </div>
          <div v-if="validInstallmentTerm.errorMessage.value" class="error" style="margin-top: 0;">{{ validInstallmentTerm.errorMessage.value }}</div>
        </div>
      </div>
      <div class="credit-card-row no-margin">
        <div class="payment-method-word description-indent " style="width: 100%; font-size: 12px; text-align: left">適用發卡銀行：{{ getInstallmentDescription() }}</div>
      </div>
    </div>

    <ConfirmButton :payment-type="'1'" :value="'確定付款'" :disabled="state.isLoading" @do-confirmation="confirm" />
  </div>
</template>
