<script setup lang="ts">
import { computed, getCurrentInstance, onMounted, onBeforeUnmount, reactive, watch } from 'vue'
import { formatCurrency, getDueDate } from '@/plugins/order'
import { useBillingStore } from '@/stores'
import ConfirmButton from '@/components/ConfirmButton.vue'

// Broadcast Channel 監聽器
let broadcastChannel = null

// 檢查 URL 查詢參數中的付款狀態
const checkUrlParameters = () => {
  try {
    const urlParams = new URLSearchParams(window.location.search);
    const paymentHash = urlParams.get('paymentHash');

    if (paymentHash) {
      console.log('[LinePay] 從 URL 參數中檢測到付款 hash:', paymentHash);
      console.log('[LinePay] 所有 URL 參數:', Object.fromEntries(urlParams.entries()));

      // 清除 URL 參數，避免重載時重複處理
      // const cleanUrl = window.location.pathname;
      // window.history.replaceState({}, document.title, cleanUrl);
      alert('paymentHash: ' + paymentHash);
      return true
    }

    return false;
  } catch (e) {
    console.error('[LinePay] URL 參數檢查錯誤:', e);
    return false;
  }
};

const emit = defineEmits(['update-disable-payment'])
const api104 = getCurrentInstance().proxy.$api104
const billingStore = useBillingStore()
const orderInfos = billingStore.orderInfos
const state = reactive({
  isLoading: false,
  idTokenHash: computed(() => billingStore.idTokenHash),
  config: computed(() => ({
    headers: {
      '104-Pay-Hmac': billingStore.paymentHash,
      'Id-Token-Hash': state.idTokenHash
    }
  })),
  totalAmount: computed(() => formatCurrency(billingStore.paymentTotalAmount)),
  dueDate: computed(() => getDueDate(orderInfos)),
  buttonVisible: true // 用來控制按鈕顯示/隱藏
})

const handleLinePay = async () => {
  // 立即禁用按鈕防止重複點擊
  emit('update-disable-payment', true)
  state.isLoading = true

  try {
    const response = await api104.post(
      '/webapis/pay/line-pay',
      {
        callbackUrl: window.location.href
      },
      state.config
    )

    console.log('[LinePay] response: ', response)

    if (response && response.data && response.data.success) {
      // 取得支付資料
      const paymentData = response.data.data

      // 建立並提交表單
      submitPaymentForm(paymentData)

      // 提交表單後隱藏按鈕
      state.buttonVisible = false

      // 重要: 重新啟用付款按鈕，允許使用者選擇其他付款方式
      emit('update-disable-payment', false)

      // 保持API成功提示
      console.log('[LinePay] LINE Pay 付款頁面已在新視窗中開啟')

      // 成功後不再執行後面的重設邏輯
      return
    } else {
      // 處理錯誤回應
      console.error('[LinePay] LINE Pay API 回應失敗:', response)

      // 可以在這裡加入其他錯誤處理邏輯
      // const result = getFailedResult(billingStore.orderInfos, response)
      // if (window.payFailed) {
      //   window.payFailed(result)
      // }
      // billingStore.updateApiResponse(result.errCode, result.errDesc)
    }
  } catch (error) {
    // 處理 API 呼叫異常
    console.error('[LinePay] 呼叫 LINE Pay API 發生錯誤:', error)
  } finally {
    // 只有在按鈕仍然可見的情況下才重新啟用它
    if (state.buttonVisible) {
      state.isLoading = false
      emit('update-disable-payment', false)
    }
  }
}

/**
 * 提交付款表單到藍新金流
 * @param paymentData - 從 API 獲取的支付資料
 */
const submitPaymentForm = (paymentData) => {
  // 建立表單元素
  const form = document.createElement('form')
  form.method = 'post'
  form.action = paymentData.url
  form.style.display = 'none'

  // 設定在新分頁開啟
  form.target = '_blank'

  // 準備表單欄位
  const fields = {
    MerchantID: paymentData.MerchantID,
    TradeInfo: paymentData.TradeInfo,
    TradeSha: paymentData.TradeSha,
    Version: paymentData.Version,
    EncryptType: paymentData.EncryptType
  }

  // 建立各個表單欄位
  Object.entries(fields).forEach(([key, value]) => {
    const input = document.createElement('input')
    input.type = 'hidden'
    input.name = key
    input.value = value
    form.appendChild(input)
  })

  // 將表單添加到文檔並提交
  document.body.appendChild(form)
  form.submit()

  // 提交後移除表單
  setTimeout(() => {
    document.body.removeChild(form)
  }, 100)
}

// 監視活動付款類型的變化
watch(
  () => billingStore.activeType,
  (newActiveType) => {
    // 當切換到其他付款方式或返回首頁時，重置狀態
    if (newActiveType !== 'LinePay') {
      state.buttonVisible = true
      state.isLoading = false
      emit('update-disable-payment', false)
    }
  }
)

// 監聽來自支付結果頁面的訊息
const handlePaymentMessage = (event) => {
  // 打印接收到的所有消息和來源
  console.log('[LinePay] 收到訊息:', event);
  console.log('[LinePay] 訊息來源:', event.origin);
  console.log('[LinePay] 訊息內容:', event.data);

  // 先檢查是否為 LINE_PAY_CALLBACK 格式
  if (event.data && event.data.type === 'LINE_PAY_CALLBACK') {
    console.log('[LinePay] 收到 LINE_PAY_CALLBACK 訊息:', event.data);
    processPaymentResult(event.data.status === 'success', event.data.timestamp);
    return;
  }

  // 為了兼容性，也檢查舊的 LINEPAY_PAYMENT_COMPLETE 格式
  if (event.data && event.data.type === 'LINEPAY_PAYMENT_COMPLETE') {
    console.log('[LinePay] 收到 LINEPAY_PAYMENT_COMPLETE 訊息:', event.data);
    processPaymentResult(event.data.success, event.data.timestamp);
    return;
  }
  
  // 檢查是否為 LINE_PAY_PARAMS 格式（新增的 Broadcast Channel API 格式）
  if (event.data && event.data.type === 'LINE_PAY_PARAMS') {
    console.log('[LinePay] 收到 LINE_PAY_PARAMS 訊息:', event.data);
    alert('收到支付參數: ' + JSON.stringify(event.data.params, null, 2));
    // 假設成功，也可以根據參數進行判斷
    processPaymentResult(true, event.data.timestamp);
    return;
  }
};

// 處理付款結果的統一函數
const processPaymentResult = (isSuccess, timestamp) => {
  // 檢查是否已經處理過同樣的付款結果
  const lastProcessedTimestamp = localStorage.getItem('lastProcessedPaymentTimestamp') || '0';

  // 如果已經處理過相同時間戳的付款結果，則跳過
  if (timestamp && timestamp.toString() === lastProcessedTimestamp) {
    console.log('[LinePay] 已經處理過相同時間戳的付款結果，跳過此次處理');
    return;
  }

  if (isSuccess) {
    // 付款成功
    console.log('[LinePay] 處理付款成功事件，時間戳:', timestamp);
    alert('付款完成');
    state.buttonVisible = false;
  } else {
    // 付款失敗
    console.log('[LinePay] 處理付款失敗事件，時間戳:', timestamp);
    alert('付款失敗');
    state.isLoading = false;
    emit('update-disable-payment', false);
  }

  // 記錄已處理的時間戳，避免重複處理
  if (timestamp) {
    localStorage.setItem('lastProcessedPaymentTimestamp', timestamp.toString());
  }
};

// 使用 Broadcast Channel API 監聽付款結果
const setupBroadcastChannel = () => {
  try {
    // 如果已經有一個 channel，先關閉它
    if (broadcastChannel) {
      broadcastChannel.close();
    }
    
    // 創建新的 Broadcast Channel
    broadcastChannel = new BroadcastChannel('line-pay-channel');
    
    // 監聽訊息
    broadcastChannel.onmessage = (event) => {
      console.log('[LinePay] 從 Broadcast Channel 收到訊息:', event.data);
      
      // 處理來自 LINE Pay 結果頁面的訊息
      if (event.data && event.data.type === 'LINE_PAY_PARAMS') {
        alert('透過 Broadcast Channel 收到支付參數: ' + JSON.stringify(event.data.params, null, 2));
        processPaymentResult(true, event.data.timestamp);
      }
    };
    
    console.log('[LinePay] Broadcast Channel 已設置');
  } catch (error) {
    console.error('[LinePay] 設置 Broadcast Channel 失敗:', error);
  }
};

// 每秒檢查 localStorage 中的付款狀態
// 返回類型: 布林值，指出是否找到付款狀態
// lastProcessedTimestamp: 上次處理的時間戳，避免重複處理相同的付款狀態
const checkLocalStorageForPaymentStatus = (lastProcessedTimestamp = '0') => {
  try {
    // 一般需要檢查的支付狀態相關鍵值
    const paymentStatus = localStorage.getItem('linePayStatus');
    const timestamp = localStorage.getItem('linePayTimestamp') || Date.now().toString();
    
    // 輸出目前 localStorage 的狀態以便於追蹤
    console.log(`[LinePay] 檢查 localStorage: `, { 
      paymentStatus, 
      timestamp, 
      lastProcessedTimestamp,
      currentTime: new Date().toLocaleTimeString()
    });
    
    // 如果有付款狀態且尚未處理過
    if (paymentStatus && timestamp > lastProcessedTimestamp) {
      console.log(`[LinePay] 在 localStorage 中找到新的付款狀態:`, paymentStatus);
      
      if (paymentStatus === 'true' || paymentStatus === true) {
        // 付款成功
        console.log('[LinePay] 付款成功!');
        alert('付款完成');
        state.buttonVisible = false;
      } else {
        // 付款失敗
        console.log('[LinePay] 付款失敗!');
        alert('付款失敗');
        state.isLoading = false;
        emit('update-disable-payment', false);
      }
      
      return true;
    }
    
    return false;
  } catch (e) {
    console.error('[LinePay] 檢查 localStorage 時出錯:', e);
    return false;
  }
};

// 確保元件掛載時狀態被重置
onMounted(() => {
  // 確保首次載入時狀態正確
  state.buttonVisible = true
  state.isLoading = false
  emit('update-disable-payment', false)

  // 添加消息監聽器
  window.addEventListener('message', handlePaymentMessage);
  
  // 初始化 Broadcast Channel
  setupBroadcastChannel();

  // 設定追蹤變數
  let paymentStatusFound = false;
  let lastProcessedTimestamp = '0';
  
  // 立即回執行一次 URL 參數檢查
  paymentStatusFound = checkUrlParameters();

  // 如果 URL 中沒有找到付款狀態，立即檢查 localStorage
  if (!paymentStatusFound) {
    const result = checkLocalStorageForPaymentStatus(lastProcessedTimestamp);
    if (result) {
      paymentStatusFound = true;
      lastProcessedTimestamp = Date.now().toString();
    }
  }

  // 設置每秒檢查 localStorage
  const localStorageCheckInterval = setInterval(() => {
    // 如果已經找到付款狀態，停止檢查
    if (paymentStatusFound) {
      console.log('[LinePay] 已找到付款狀態，停止檢查 localStorage');
      clearInterval(localStorageCheckInterval);
      return;
    }
    
    // 每秒檢查一次 localStorage
    console.log('[LinePay] 定期檢查 localStorage 中的付款狀態...');
    const result = checkLocalStorageForPaymentStatus(lastProcessedTimestamp);
    if (result) {
      paymentStatusFound = true;
      lastProcessedTimestamp = Date.now().toString();
      clearInterval(localStorageCheckInterval);
    }
  }, 1000);

  // 每兩秒檢查一次 URL 參數
  const urlCheckInterval = setInterval(() => {
    // 如果已經找到付款狀態，停止檢查
    if (paymentStatusFound) {
      console.log('[LinePay] 已找到付款狀態，停止檢查 URL');
      clearInterval(urlCheckInterval);
      return;
    }

    // 檢查 URL 參數
    console.log('[LinePay] 檢查 URL 參數，目前 URL:', window.location.href);
    const urlHasPaymentStatus = checkUrlParameters();
    if (urlHasPaymentStatus) {
      console.log('[LinePay] 在定期檢查中找到 URL 付款狀態參數');
      paymentStatusFound = true;
      clearInterval(urlCheckInterval);
      clearInterval(localStorageCheckInterval);
    }
  }, 2000);

  // 在組件卸載後清除定時器
  onBeforeUnmount(() => {
    clearInterval(localStorageCheckInterval);
    clearInterval(urlCheckInterval);
    window.removeEventListener('message', handlePaymentMessage);
    
    // 關閉 Broadcast Channel
    if (broadcastChannel) {
      broadcastChannel.close();
      broadcastChannel = null;
    }
  });
})
</script>

<template>
  <div ref="payment-method" class="payment-method" style="position:relative">
    <div v-if="state.buttonVisible" class="payment-info-message">
      <p>確定 LinePay 付款</p>
      <p><strong>提醒您 - 您即將離開 104 網域</strong></p>
      <ConfirmButton
        :payment-type="'10'"
        :value="'確定付款'"
        :disabled="state.isLoading"
        @do-confirmation="handleLinePay"
      />
    </div>
    <div v-else class="payment-info-message">
      <p>LINE Pay 付款頁面已在新視窗中開啟，請前往完成付款。</p>
      <p>如果您沒有看到付款頁面，請檢查瀏覽器是否封鎖了彈出視窗。</p>
    </div>
  </div>
</template>

<style scoped>
.payment-info-message {
  margin-top: 20px;
  padding: 15px;
  background-color: #f8f9fa;
  border-radius: 4px;
  border-left: 4px solid #00afb8;
  color: #333;
}
</style>
