<script setup lang="ts">
import { reactive, onMounted, computed, getCurrentInstance } from 'vue'
import { ApiResponse } from 'axios'
import type { OrderInfo, Result, FailedResult } from '@/types'
import { useBillingStore } from '@/stores'
import checkImage from '@/assets/images/icon-check-circle.svg'

const props = defineProps<{
  paymentHash: string,
  orderInfos: OrderInfo[]
}>()

const billingStore = useBillingStore()
const api104 = getCurrentInstance().proxy.$api104
const state = reactive({
  idTokenHash: computed(() => billingStore.idTokenHash),
  message: null,
  paymentStatus: null,
  isLoading: true,
  checkIcon: import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat('/img/icon-check-circle.svg') : checkImage
})

const getSuccessResult = (data) => {
  return {
    buId: data.buId,
    paymentType: null,
    paymentStatus: data.paymentStatus,
    virtualAccount: null,
    approveCode: null,
    customerTransDate: data.customerTransDate,
    orderIdList: data.orderIdList
  } as Result
}

const getFailedResult = (orderInfoList: OrderInfo[], message) => {
  const result = {
    buId: null,
    paymentType: null,
    paymentStatus: 0,
    customerTransDate: null,
    errCode: null,
    errDesc: message,
    gatewayName: null,
    orderIdList: null
  } as FailedResult
  if (orderInfoList.length > 0) {
    result.buId = orderInfoList[0].buId
    result.orderIdList = orderInfoList.map(value => value.orderId)
  }
  return result
}

onMounted(async () => {
  const response = await api104.put<ApiResponse>(
    '/webapis/pay/free',
    null,
    {
      headers: {
        '104-Pay-Hmac': props.paymentHash,
        'Id-Token-Hash': state.idTokenHash
      }
    }
  )
  state.isLoading = false
  if (response && response.data) {
    if (response.data.data) {
      const result = getSuccessResult(response.data.data)
      state.paymentStatus = result.paymentStatus
      if (window.payComplete) {
        window.payComplete(result)
      }
    } else {
      state.message = response.data.message ? response.data.message : response.data
      const orderInfos = props.orderInfos as OrderInfo[]
      const result = getFailedResult(orderInfos, state.message)
      state.paymentStatus = result.paymentStatus
      if (window.payFailed) {
        window.payFailed(result)
      }
    }
  }
})
</script>

<template>
  <div ref="payment-method" class="payment-method payment-message" style="position:relative">
    <loading-component
      loader="spinner"
      :active="state.isLoading"
      :is-full-page="false"
    ></loading-component>
    <template v-if="state.paymentStatus === 1">
      <div class="pay-success-row">
        <img
          class="icon"
          :src="state.checkIcon"
          alt="check-circle"
        />
        <span class="title">該訂單無需繳款</span>
      </div>
      <div
        class="pay-success-row row-interval"
      >
        <span class="Thanks">感謝您。</span>
      </div>
    </template>
    <template v-if="state.paymentStatus === 0">
      <div class="pay-success-row">
        <span class="icon alarm">i</span>
        <span class="title">購買失敗</span>
      </div>
      <div class="pay-success-row">
        <span class="error">{{ state.message }}</span>
      </div>
    </template>
    <template v-if="state.paymentStatus === null">
      <div class="pay-success-row">
        <span class="icon alarm">i</span>
        <span class="title">購買中</span>
      </div>
      <div
        class="pay-success-row row-interval"
      >
        <span class="Thanks">請稍後</span>
      </div>
    </template>
  </div>
</template>
