import { defineStore } from 'pinia'
import { OrderInfo, Result, SaveCardInfo, InstallmentInfo } from '@/types'

export const useBillingStore = defineStore('billing', {
  state: () => {
    return {
      isLoading: false,
      customWidth: '1200px',
      apiResponse: {
        errCode: '',
        errDesc: ''
      },
      defaultOpenPaymentType: null,
      defaultAgreeSaveCard: null,
      orderPaymentType: null,
      isMobile: false,
      showPayment: true,
      activeType: null,
      rowNumber: null,
      idTokenHash: '',
      paymentHash: '',
      orderInfos: [] as OrderInfo[],
      paymentTotalAmount: 0,
      result: {
        buId: null,
        paymentType: null,
        paymentStatus: 0,
        virtualAccount: null,
        approveCode: null,
        customerTransDate: null,
        orderIdList: null,
        saveCardStatus: 0
      },
      saveCardInfo: {
        orderSaveCardType: 0,
        pan: null,
        expDate: null,
        saveCardInfoStatus: 0,
        saveCardExpiredMessage: null
      } as SaveCardInfo,
      installmentInfos: [] as InstallmentInfo[]
    }
  },
  actions: {
    updateLoading (isLoading: boolean) {
      this.isLoading = isLoading
    },
    updateWidth (width: string) {
      this.customWidth = width
    },
    updateApiResponse (errCode: string, errDesc: string) {
      this.apiResponse.errCode = errCode
      this.apiResponse.errDesc = errDesc
    },
    updateDefaultOpenPaymentType (defaultOpenPaymentType: number) {
      this.defaultOpenPaymentType = defaultOpenPaymentType
    },
    updateDefaultAgreeSaveCard (defaultAgreeSaveCard: number) {
      this.defaultAgreeSaveCard = defaultAgreeSaveCard
    },
    updateOrderPaymentType (orderPaymentType: string) {
      this.orderPaymentType = orderPaymentType
    },
    updateMobile (isMobile: boolean) {
      this.isMobile = isMobile
    },
    updateShowPayment (showPayment: boolean) {
      this.showPayment = showPayment
    },
    updateActiveType (activeType: string) {
      this.activeType = activeType
    },
    updateRowNumber (rowNumber: number) {
      this.rowNumber = rowNumber
    },
    updateResult (result: Result) {
      this.result = result
    },
    updateIdTokenHash (idTokenHash: string) {
      this.idTokenHash = idTokenHash
    },
    updatePaymentHash (paymentHash: string) {
      this.paymentHash = paymentHash
    },
    updateOrderInfos (orderInfos: OrderInfo[]) {
      this.orderInfos = orderInfos
    },
    updatePaymentTotalAmount (paymentTotalAmount: number) {
      this.paymentTotalAmount = paymentTotalAmount
    },
    updateSaveCardInfo (saveCardInfo: SaveCardInfo) {
      this.saveCardInfo = saveCardInfo
    },
    updateInstallmentInfos (installmentInfos: InstallmentInfo[]) {
      this.installmentInfos = installmentInfos
    }
  }
})
