/**
 * 產生 sha256 HMAC 簽章, 當瀏覽器不支援時，回傳空值。
 * 不用太新的演算法是為了確保瀏覽器支援。
 * @param data 要簽章的資料，資料串接的順序，需與 java 後端一致，方能正確驗證
 * @param hmacKey 簽章金鑰
 * @returns 簽章 base64 字串, 如瀏覽器不支援回傳空值
 */
export async function generateHmacSignature(data: string, hmacKey: string) {

  // 瀏覽器不支援時回傳空值
  if (typeof TextEncoder === 'undefined' || !crypto.subtle) {
    return '';
  }

  try {
    // sha256 的 key 至少需 256 bits(32 Bytes)，當長度不足時前面補 0
    hmacKey = hmacKey.length < 32 ? hmacKey.padStart(32, '0') : hmacKey

    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      "raw",
      encoder.encode(hmacKey),
      { name: "HMAC", hash: { name: "SHA-256" } },
      false,
      ["sign"]
    );

    const signature = await crypto.subtle.sign(
      "HMAC",
      key,
      encoder.encode(data)
    );

    // 轉換為 Base64 URL Safe encode
    return btoa(String.fromCharCode(...new Uint8Array(signature)))
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=+$/, '');

    // eslint-disable-next-line @typescript-eslint/no-unused-vars
  } catch (e) { // 發生錯誤時，回傳空值以避免使用者操作流程中斷
    return '';
  }
}
