<script setup lang="ts">
import visa from '@/assets/images/btn_credit_visa_off.svg'
import master from '@/assets/images/btn_credit_master_off.svg'
import jcb from '@/assets/images/btn_credit_jcb_off.svg'
import type { FailedResult, OrderInfo, Result } from '@/types'
import { computed, getCurrentInstance, onMounted, reactive } from 'vue'
import { useRouter } from 'vue-router'
import { useBillingStore } from '@/stores'
import { useField, useForm } from 'vee-validate'
import ConfirmButton from '@/components/ConfirmButton.vue'
import clearImage from '@/assets/images/delete.svg'
import undoClearImage from '@/assets/images/revert.svg'
import { goToFirstError } from '@/plugins/validators'
import { generateHmacSignature } from '@/plugins/signature'

const year = new Date().getFullYear() % 100

const emit = defineEmits(['update-disable-payment'])
const router = useRouter()
const billingStore = useBillingStore()
const currentInstance = getCurrentInstance()
const api104 = currentInstance.proxy.$api104
const saveCardInfo = billingStore.saveCardInfo
const orderSaveCardType = billingStore.saveCardInfo.orderSaveCardType
const isSaveCardOrder = (orderSaveCardType !== 0) as boolean
const hasSaveCardInfo = !!(isSaveCardOrder && saveCardInfo.pan && saveCardInfo.expDate)
const isSubscriptionOrderWithCardInfo = (billingStore.saveCardInfo.orderSaveCardType === 2 && hasSaveCardInfo) as boolean
// 綁定信用卡資料是否有效
const isValidSaveCardInfo = (saveCardInfo.saveCardInfoStatus === 1 || saveCardInfo.saveCardInfoStatus === 2) as boolean
// 同意綁卡的 checkbox flag, 若有綁卡資料時 (Pn交易) 則 checkbox 為勾選
const defaultAgreeSaveCard = isValidSaveCardInfo || billingStore.defaultAgreeSaveCard === 1 || billingStore.defaultAgreeSaveCard === null || billingStore.defaultAgreeSaveCard === undefined
const saveCardTypeMapping = {
  4: 'visa',
  5: 'mastercard',
  3: 'jcb'
}

const getSaveCardExpiredMessage = () => {
  const saveCardInfoStatus = saveCardInfo.saveCardInfoStatus
  if (saveCardInfoStatus === 3) {
    return '此信用卡已過期，請點選清除並重新設定其他信用卡。'
  } else if (saveCardInfoStatus === 2) {
    return '此信用卡即將到期，請盡速重新設定其他信用卡。'
  } else {
    return ''
  }
}

const {
  handleSubmit,
  resetForm
} = useForm()

const state = reactive({
  isLoading: false,
  cardTypes: [{
    name: 'visa',
    icon: computed(() => getIconUrl('/img/btn_credit_visa_off.svg', visa)),
    isActive: false
  },
  {
    name: 'mastercard',
    icon: computed(() => getIconUrl('/img/btn_credit_master_off.svg', master)),
    isActive: false
  },
  {
    name: 'jcb',
    icon: computed(() => getIconUrl('/img/btn_credit_jcb_off.svg', jcb)),
    isActive: false
  }],
  creditCardInfo: computed(() => ({
    pan: validCardNumber.value.value,
    cvv2: validSecurityCode.value.value,
    expDate: '20'.concat(validExpYear.value.value).concat(validExpMonth.value.value)
  })),
  idTokenHash: computed(() => billingStore.idTokenHash),
  config: computed(() => ({
    headers: {
      '104-Pay-Hmac': billingStore.paymentHash,
      'Id-Token-Hash': state.idTokenHash,
      'Billing-Authorization': state.hmacSignature,
    }
  })),
  options: {
    creditCard: true,
    delimiter: ' ',
    onCreditCardTypeChanged: type => {
      state.cardTypes.forEach(cardType => {
        cardType.isActive = cardType.name === type
      })
    }
  },
  result: computed(() => billingStore.result as Result),
  expMonthArray: Array.from({ length: 12 }, (_, i) => (i + 1).toString().padStart(2, '0')),
  expYearArray: Array.from({ length: 10 }, (_, i) => ((year + i) % 100).toString()),
  saveCardInfo: { // 綁卡資訊
    // 是否有綁卡資訊
    isSaveCard: hasSaveCardInfo,
    // 綁卡卡號
    saveCardPan: hasSaveCardInfo ? saveCardInfo.pan.replace(/(.{4})/g, '$1 ').trim() : '',
    // 綁卡有效年
    saveCardValidYear: hasSaveCardInfo ? saveCardInfo.expDate.slice(2, 4) : '',
    // 綁卡有效月
    saveCardValidMonth: hasSaveCardInfo ? saveCardInfo.expDate.slice(4, 6) : '',
    // 是否為網進制
    isWebOrder: hasSaveCardInfo ? isValidSaveCardInfo && !isSubscriptionOrderWithCardInfo : true,
    // 綁卡效期狀態
    saveCardInfoStatus: hasSaveCardInfo ? saveCardInfo.saveCardInfoStatus : 0,
    // 綁卡效期訊息
    saveCardExpiredMessage: hasSaveCardInfo ? getSaveCardExpiredMessage() : '',
    // 同意綁卡的 checkbox flag是否勾選, (過刷綁卡類型為必勾選)
    agreeSaveCardCheckbox: orderSaveCardType === 3 || defaultAgreeSaveCard,
    // 是否顯示同意綁卡的 checkbox
    isShowAgreeCheckbox: isSaveCardOrder && saveCardInfo.saveCardInfoStatus !== 3 && (orderSaveCardType === 1 || orderSaveCardType === 3 || (orderSaveCardType === 2 && !hasSaveCardInfo)),
    // 是否顯示綁卡清除按鈕
    isShowClearButton: isSaveCardOrder && hasSaveCardInfo,
    // 是否顯示綁卡復原按鈕
    isShowUndoClearButton: false,
    clearIcon: import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat('/img/delete.svg') : clearImage,
    undoClearIcon: import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat('/img/revert.svg') : undoClearImage
  },
  memento: {} as any
})

// 有綁卡時, 跳過驗證, 讓客戶可以付款, 使用 computed 是讓清除卡號後, 可以更新驗證規則
const validCardNumberRule = computed(() => (state.saveCardInfo.isSaveCard ? {} : { required: true, digitNumber: '信用卡號 格式錯誤' }))
const validSecurityCodeRule = computed(() => (state.saveCardInfo.isSaveCard ? {} : { required: true, securityCode: true }))
const validExpMonthRule = computed(() => (state.saveCardInfo.isSaveCard ? {} : { required: true, month: true }))
const validExpYearRule = computed(() => (state.saveCardInfo.isSaveCard ? {} : { required: true, year: true }))

// 綁定表單欄位資料,驗證規則及預設值
const validCardNumber = useField('cardNumber', validCardNumberRule, { initialValue: '' })
const validSecurityCode = useField('securityCode', validSecurityCodeRule, { initialValue: '' })
const validExpMonth = useField('expMonth', validExpMonthRule, { initialValue: '' })
const validExpYear = useField('expYear', validExpYearRule, { initialValue: '' })

const getIconUrl = (iconPath: string, fallback: string) => {
  return import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat(iconPath) : fallback
}

const paySuccess = response =>
  response &&
  response.data &&
  response.data.data &&
  response.data.data.paymentStatus

const convertSaveCardStatusCallBack = (saveCardStatus: number): number => {
  if (saveCardStatus !== null && saveCardStatus !== undefined) {
    return saveCardStatus === 3 ? 1 : saveCardStatus
  }

  return 0
}

// 提供 handleSubmit 處理驗證失敗後的邏輯, Focus 到第一個錯誤欄位
const errorCallBack = ({ results }) => goToFirstError(currentInstance.refs.observer as Element, results)

const getSuccessResult = (orderInfos: OrderInfo[] = [], response: any = {}) => {
  const data = response?.data?.data || {}
  return {
    buId: orderInfos[0]?.buId || null,
    paymentType: '1',
    paymentStatus: 1,
    virtualAccount: null,
    approveCode: data.authCode || '',
    customerTransDate: data.transDateTime || null,
    orderIdList: orderInfos.map(value => value.orderId),
    saveCardStatus: convertSaveCardStatusCallBack(data.saveCardStatus),
    installmentTerm: 0
  } as Result
}

const getFailedResult = (orderInfos: OrderInfo[] = [], response: any = {}) => {
  const data = response?.data?.data || {}
  return {
    buId: orderInfos[0]?.buId || null,
    paymentType: '1',
    paymentStatus: 0,
    customerTransDate: data.transDateTime || null,
    errCode: data.errCode || '',
    errDesc: data.errDesc || response?.data?.message || '',
    gatewayName: data.gatewayName || '',
    orderIdList: orderInfos.map(value => value.orderId),
    saveCardStatus: convertSaveCardStatusCallBack(data.saveCardStatus)
  } as FailedResult
}

const updateResult = (currentResult: Result) => {
  if (state.result !== currentResult) {
    billingStore.updateResult(currentResult)
    if (window.payComplete) {
      window.payComplete(currentResult)
    }
  }
}

const creditAuth = async () => {
  state.hmacSignature = await generateHmacSignature(`${state.creditCardInfo.pan}${state.creditCardInfo.expDate}${state.creditCardInfo.cvv2}`, billingStore.paymentHash)

  return await api104.post(
    '/webapis/pay/credit',
    {
      pan: state.creditCardInfo.pan,
      cvv2: state.creditCardInfo.cvv2,
      expDate: state.creditCardInfo.expDate
    },
    state.config
  )
}

const creditSaveCardAuth = async () => {
  state.hmacSignature = await generateHmacSignature(`${state.creditCardInfo.pan}${state.creditCardInfo.expDate}${state.creditCardInfo.cvv2}`, billingStore.paymentHash)

  return await api104.post(
    '/webapis/pay/credit/save',
    {
      pan: state.creditCardInfo.pan,
      cvv2: state.creditCardInfo.cvv2,
      expDate: state.creditCardInfo.expDate === '20' ? '' : state.creditCardInfo.expDate,
      agreeSaveCard: 1
    },
    state.config
  )
}

const confirm = handleSubmit(async () => {
  emit('update-disable-payment', true)
  state.isLoading = true

  // 判斷是綁卡訂單且同意綁卡 flag 為 true 則呼叫綁卡授權 API, 否則呼叫一般信用卡授權 API
  const response = billingStore.saveCardInfo.orderSaveCardType !== 0 && state.saveCardInfo.agreeSaveCardCheckbox ? await creditSaveCardAuth() : await creditAuth()
  state.isLoading = false
  if (paySuccess(response)) {
    billingStore.updateShowPayment(false)

    await router.push({
      name: 'CreditCardSuccess',
      params: {
        paymentType: '1',
        saveCardStatus: response.data.data.saveCardStatus || 0
      }
    })
    updateResult(getSuccessResult(billingStore.orderInfos, response))
  } else {
    emit('update-disable-payment', false)

    const result = getFailedResult(billingStore.orderInfos, response)
    if (response && response.data && response.data.data && response.data.data.errStatus === 499) {
      clearSaveCardInfo()
    }
    if (window.payFailed) {
      window.payFailed(result)
    }
    billingStore.updateApiResponse(result.errCode, result.errDesc)
    await router.push({
      name: 'CreditCardFail'
    })
  }
}, errorCallBack)

const clearSaveCardInfo = () => {
  if (!hasSaveCardInfo) {
    resetForm()
    return
  }

  state.memento = {
    cardType: state.cardType,
    saveCardInfo: {
      isSaveCard: state.saveCardInfo.isSaveCard,
      saveCardPan: state.saveCardInfo.saveCardPan,
      saveCardValidYear: state.saveCardInfo.saveCardValidYear,
      saveCardValidMonth: state.saveCardInfo.saveCardValidMonth,
      isWebOrder: state.saveCardInfo.isWebOrder,
      saveCardExpiredMessage: state.saveCardInfo.saveCardExpiredMessage,
      agreeSaveCardCheckbox: state.saveCardInfo.agreeSaveCardCheckbox,
      isShowAgreeCheckbox: state.saveCardInfo.isShowAgreeCheckbox,
      isShowUndoClearButton: state.saveCardInfo.isShowUndoClearButton
    }
  }

  state.cardType = null
  state.saveCardInfo.isSaveCard = false
  state.saveCardInfo.saveCardPan = ''
  state.saveCardInfo.saveCardValidYear = ''
  state.saveCardInfo.saveCardValidMonth = ''
  state.saveCardInfo.isWebOrder = true
  state.saveCardInfo.saveCardExpiredMessage = ''
  state.saveCardInfo.agreeSaveCardCheckbox = true
  state.saveCardInfo.isShowAgreeCheckbox = true
  state.saveCardInfo.isShowClearButton = false
  state.saveCardInfo.isShowUndoClearButton = orderSaveCardType === 2
  resetForm()

  // 網進制 & 過刷類型則把pinia內綁卡內容清除
  if (orderSaveCardType === 1 || orderSaveCardType === 3) {
    billingStore.updateSaveCardInfo({
      orderSaveCardType: billingStore.saveCardInfo.orderSaveCardType,
      pan: '',
      expDate: '',
      saveCardInfoStatus: 0
    })
  }

  saveCardType()
}

const undoClearSaveCardInfo = () => {
  resetForm()
  const memento = state.memento
  const saveCardInfo = memento.saveCardInfo

  state.cardType = memento.cardType
  state.saveCardInfo.isSaveCard = saveCardInfo.isSaveCard
  state.saveCardInfo.saveCardPan = saveCardInfo.saveCardPan
  state.saveCardInfo.saveCardValidYear = saveCardInfo.saveCardValidYear
  state.saveCardInfo.saveCardValidMonth = saveCardInfo.saveCardValidMonth
  state.saveCardInfo.isWebOrder = saveCardInfo.isWebOrder
  state.saveCardInfo.saveCardExpiredMessage = saveCardInfo.saveCardExpiredMessage
  state.saveCardInfo.agreeSaveCardCheckbox = saveCardInfo.agreeSaveCardCheckbox
  state.saveCardInfo.isShowAgreeCheckbox = saveCardInfo.isShowAgreeCheckbox
  state.saveCardInfo.isShowClearButton = true
  state.saveCardInfo.isShowUndoClearButton = false

  saveCardType()
}

const saveCardType = () => {
  const saveCardPan = state.saveCardInfo.saveCardPan
  const type = saveCardTypeMapping[saveCardPan.charAt(0)]
  state.cardTypes.forEach(cardType => {
    cardType.isActive = cardType.name === type
  })
}

onMounted(() => {
  // 有綁卡的話, select 卡別
  if (hasSaveCardInfo) {
    saveCardType()
  }
})
</script>

<template>
  <div ref="observer" class="payment-method" style="position:relative">
    <loading-component v-if="state.isLoading" loader="spinner" :active="true" :is-full-page="false" />

    <div class="payment-method-row" :style="state.saveCardInfo.isWebOrder ? 'border-bottom-width: 1px' : 'border-bottom-width: 0px'">
      <!-- 信用卡別區塊 -->
      <div class="credit-card-row">
        <label class="payment-method-word">信用卡別</label>
        <div
          v-for="cardType in state.cardTypes"
          :key="cardType.name"
          :style="{ backgroundImage: `url(${cardType.icon})` }"
          :class="['card-type', { active: cardType.isActive}]"
        ></div>
      </div>

      <!-- 信用卡號區塊 -->
      <div class="credit-card-row no-margin">
        <label class="payment-method-word">信用卡號</label>
        <div class="credit-card-column">
          <div class="cleave-wrapper">
            <cleave
              v-if="!state.saveCardInfo.isSaveCard"
              v-model="validCardNumber.value.value"
              inputmode="numeric"
              name="cardNumber"
              :options="state.options"
              class="credit-card-input"
              :class="{ 'input-error': validCardNumber.errorMessage.value }"
              placeholder="0000 0000 0000 0000"
              @blur="validCardNumber.validate()"
            ></cleave>
            <input
              v-else
              v-model="state.saveCardInfo.saveCardPan"
              class="credit-card-input credit-card-input-disable-input"
              readonly
            />
            <button v-if="state.saveCardInfo.isShowClearButton" class="toggle-save-card-btn" @click="clearSaveCardInfo">
              <img class="icon" :src="state.saveCardInfo.clearIcon" alt="clearIcon" />
            </button>
            <button
              v-else-if="state.saveCardInfo.isShowUndoClearButton && !state.creditCardInfo.pan" class="toggle-save-card-btn"
              @click="undoClearSaveCardInfo"
            >
              <img class="icon" :src="state.saveCardInfo.undoClearIcon" alt="undoClearIcon" />
            </button>
          </div>
          <div v-if="validCardNumber.errorMessage.value" class="error">{{ validCardNumber.errorMessage.value }}</div>
          <div v-else class="reserve"></div>
        </div>
      </div>

      <!-- 有效期限區塊 -->
      <div class="credit-card-row no-margin">
        <label class="payment-method-word">有效期限</label>
        <!-- 月份欄位 -->
        <div class="credit-card-column">
          <select
            v-if="!state.saveCardInfo.isSaveCard"
            v-model="validExpMonth.value.value"
            name="expMonth"
            class="credit-card-input input-m-size"
            :class="{ 'input-error': validExpMonth.errorMessage.value }"
            autocomplete="off"
            @blur="validExpMonth.validate()"
          >
            <option v-for="(value, index) in state.expMonthArray" :key="'month' + index" :value="value">{{ value }}</option>
          </select>
          <input
            v-else v-model="state.saveCardInfo.saveCardValidMonth" class="credit-card-input credit-card-input-disable-input input-m-size"
            readonly
          />
          <div v-if="validExpMonth.errorMessage.value" class="error error-m-size">{{ validExpMonth.errorMessage.value }}</div>
          <div v-else class="reserve"></div>
        </div>
        <label class="payment-method-word word-m-size" style="width: 60px">月 / 20</label>
        <!-- 年度欄位 -->
        <div class="credit-card-column">
          <select
            v-if="!state.saveCardInfo.isSaveCard"
            v-model="validExpYear.value.value"
            name="expYear"
            class="credit-card-input input-m-size"
            :class="{ 'input-error': validExpYear.errorMessage.value }"
            autocomplete="off"
            @blur="validExpYear.validate()"
          >
            <option v-for="(value, index) in state.expYearArray" :key="'year' + index" :value="value">{{ value }}</option>
          </select>
          <input
            v-else v-model="state.saveCardInfo.saveCardValidYear" class="credit-card-input credit-card-input-disable-input input-m-size"
            readonly
          />
          <div v-if="validExpYear.errorMessage.value" class="error error-m-size">{{ validExpYear.errorMessage.value }}</div>
          <div v-else class="reserve"></div>
        </div>
        <label class="payment-method-word word-s-size" style="width: 30px">年</label>
      </div>

      <!-- 安全碼 -->
      <div v-if="!state.saveCardInfo.isSaveCard" class="credit-card-row no-margin">
        <label class="payment-method-word">安全碼</label>
        <div class="credit-card-column">
          <input
            v-model="validSecurityCode.value.value"
            inputmode="numeric"
            type="text"
            name="securityCode"
            :class="{ 'input-error': validSecurityCode.errorMessage.value }"
            class="credit-card-input input-m-size"
            placeholder="000"
            maxlength="3"
            autocomplete="off"
            @blur="validSecurityCode.validate()"
          >
          <div v-if="validSecurityCode.errorMessage.value" class="error">{{ validSecurityCode.errorMessage.value }}</div>
          <div v-else class="reserve"></div>
        </div>
      </div>

      <!-- 綁卡文案區塊 -->
      <div
        v-if="isSubscriptionOrderWithCardInfo && isValidSaveCardInfo && state.saveCardInfo.isSaveCard"
        class="credit-card-row no-margin credit-card-input-save-card-label save-card-subscription-word"
      >
        <label>您已設定此信用卡自動扣款。</label>
      </div>
      <div
        v-if="isValidSaveCardInfo && state.saveCardInfo.saveCardExpiredMessage"
        class="credit-card-row no-margin credit-card-input-save-card-label"
      >
        <label class="save-card-expired-warning-word">{{ state.saveCardInfo.saveCardExpiredMessage }}</label>
      </div>
      <div v-if="state.saveCardInfo.isShowAgreeCheckbox" class="credit-card-row no-margin credit-card-input-save-card-label">
        <input
          id="saveCardAgreeCheckbox" v-model="state.saveCardInfo.agreeSaveCardCheckbox" type="checkbox"
          :disabled="orderSaveCardType === 3 || state.saveCardInfo.isSaveCard"
        >
        <label for="saveCardAgreeCheckbox" class="credit-card-agree-checkbox-word">本人同意將此信用卡設定為常用支付方式，以利下次快速支付。</label>
      </div>
    </div>

    <ConfirmButton v-if="state.saveCardInfo.isWebOrder" :payment-type="'1'" :value="'確定付款'" :disabled="state.isLoading" @do-confirmation="confirm" />
  </div>
</template>
