export const defineCustomElement = (component, {
  plugins = [],
  globalComponents = {}
}: { plugins: (Router | Pinia)[], globalComponents: object }) =>
  VueDefineCustomElement({
    props: component.props,
    setup (props) {
      const app = createApp(component)
      app.config.globalProperties.$api104 = Instance

      // install plugins
      plugins.forEach(app.use)

      // install components
      Object.entries(globalComponents).forEach(key => app.component(key[0], key[1]))

      // 日後，如果有在App.ce.vue以外的component內，寫css的話，就要使用下面的方式，把style注入
      // app.mixin({
      //   mounted () {
      //     const insertStyles = (styles) => {
      //       if (styles?.length) {
      //         this.__style = document.createElement('style')
      //         this.__style.innerText = styles.join().replace(/\n/g, '')
      //         getNearestElementParent(this.$el).prepend(this.__style)
      //       }
      //     }
      //
      //     // load own styles
      //     insertStyles(this.$?.type.styles)
      //
      //     // load styles of child components
      //     if (this.$options.components) {
      //       for (const comp of Object.values(this.$options.components)) {
      //         // insertStyles(comp.styles)
      //       }
      //     }
      //   },
      //   unmounted () {
      //     this.__style?.remove()
      //   }
      // })

      const inst = getCurrentInstance()
      Object.assign(inst.appContext, app._context)
      Object.assign(inst.provides, app._context.provides)
      return () => h(component, props)
    },
    styles: component.styles
  })
