<script setup lang="ts">
import { ref, onMounted, onBeforeUnmount } from 'vue'

// 用於存儲接收到的參數
const receivedParams = ref({})
const isReceived = ref(false)

// Broadcast Channel 實例
let broadcastChannel = null

// 處理 URL 參數
const processUrlParams = () => {
  const urlParams = new URLSearchParams(window.location.search)
  const params = {}
  
  // 收集所有 URL 參數
  for (const [key, value] of urlParams.entries()) {
    params[key] = value
  }
  
  if (Object.keys(params).length > 0) {
    receivedParams.value = params
    isReceived.value = true
    console.log('已接收到 URL 參數:', params)
    alert('接收到 URL 參數: ' + JSON.stringify(params, null, 2))
  }
}

// 設置 Broadcast Channel 監聽
const setupBroadcastChannel = () => {
  try {
    broadcastChannel = new BroadcastChannel('line-pay-channel')
    
    broadcastChannel.onmessage = (event) => {
      console.log('從 Broadcast Channel 收到訊息:', event.data)
      
      if (event.data && event.data.type === 'LINE_PAY_PARAMS') {
        receivedParams.value = event.data.params || {}
        isReceived.value = true
        alert('透過 Broadcast Channel 收到參數: ' + JSON.stringify(event.data.params, null, 2))
      }
    }
  } catch (error) {
    console.error('設置 Broadcast Channel 失敗:', error)
  }
}

// 組件掛載時執行
onMounted(() => {
  // 處理 URL 參數
  processUrlParams()
  
  // 設置 Broadcast Channel
  setupBroadcastChannel()
  
  // 監聽 URL 變化
  window.addEventListener('popstate', processUrlParams)
})

// 組件卸載前移除監聽器
onBeforeUnmount(() => {
  window.removeEventListener('popstate', processUrlParams)
  
  // 關閉 Broadcast Channel
  if (broadcastChannel) {
    broadcastChannel.close()
    broadcastChannel = null
  }
})
</script>

<template>
  <div class="line-pay-receiver">
    <h2>Line Pay 參數接收器</h2>
    
    <div v-if="isReceived" class="params-container">
      <h3>已接收到參數</h3>
      <div class="params-list">
        <div v-for="(value, key) in receivedParams" :key="key" class="param-item">
          <strong>{{ key }}:</strong> {{ value }}
        </div>
      </div>
    </div>
    
    <div v-else class="waiting-message">
      等待接收 Line Pay 參數...
    </div>
  </div>
</template>

