<script setup lang="ts">
import { reactive } from 'vue'
import { useRouter } from 'vue-router'

const router = useRouter()

const props = withDefaults(defineProps<{
  paymentType: string,
  value?: string,
  disabled?: boolean
}>(), {
  paymentType: '',
  value: '確定此付款方式',
  disabled: false
})
const emit = defineEmits(['do-confirmation'])

const state = reactive({
  disabled: false
})

const confirm = () => {
  if (props.paymentType === '1' || props.paymentType === '10') {
    emit('do-confirmation')
  } else {
    state.disabled = true
    router.push({
      name: 'Home'
    })
    router.push({
      name: 'Complete',
      params: {
        paymentType: props.paymentType
      }
    })
  }
}
</script>

<template>
  <div class="payment-confirm">
    <input
      type="button"
      class="btn"
      :value="props.value"
      :disabled="props.disabled || state.disabled"
      @click="confirm"
    />
  </div>
</template>
