<script setup lang="ts">

interface Props {
  imageUrl: string,
  count: number,
  way: string,
  description: string,
  barcodeData: object,
  isMobileMode: boolean
}

withDefaults(defineProps<Props>(), {
  imageUrl: null,
  count: 0,
  way: '',
  description: '',
  barcodeData: null,
  isMobileMode: false
})

const getImgSrc = (barcodeData, way, id) => `data:image/png;base64,${barcodeData[`${way}BarCode${id}`]}`
const getNumber = (barcodeData, way, id) => barcodeData[`${way}Account${id}`]
</script>

<template>
  <div class="barcode-box">
    <div class="left-side">
      <span
        class="icon"
        :style="{ backgroundImage: `url(${imageUrl})` }"
      ></span>
      <span class="description">{{ description }}<br>代收專用</span>
    </div>
    <div class="right-side">
      <div>
        <template v-if="isMobileMode">
          <div style="width: 30%"></div>
        </template>
        <div v-for="i in count" :key="`${way}${i}`" class="row">
          <img :src="getImgSrc(barcodeData, way, i)" :alt="getNumber(barcodeData, way, i)" />
          <span class="number">{{ getNumber(barcodeData, way, i) }}</span>
        </div>
      </div>
    </div>
  </div>
</template>
