<script setup lang="ts">
import BarcodeBox from '@/components/BarcodeBox.vue'
import Notice from '@/components/Notice.vue'
import storeImage from '@/assets/images/icon_payment_711.svg'
import postImage from '@/assets/images/icon_payment_post.svg'
import botImage from '@/assets/images/icon_payment_bank.svg'
import checkImage from '@/assets/images/icon-check-circle.svg'
import copyImage from '@/assets/images/icon-16-tool-icon-copy.svg'
import { formatCurrency, getDueDate, getOrderInfoList } from '@/plugins/order'
import { computed, getCurrentInstance, onMounted, reactive } from 'vue'
import type { OrderInfo, Result } from '@/types'
import { useBillingStore } from '@/stores'
import useClipboard from 'vue-clipboard3'
import Toast from '@/components/Toast.vue'

interface Props {
  paymentType: string
}

const props = withDefaults(defineProps<Props>(), {
  paymentType: ''
})

const emit = defineEmits(['update-disable-payment'])
const billingStore = useBillingStore()
const paymentHash = billingStore.paymentHash
const orderInfos = billingStore.orderInfos
const api104 = getCurrentInstance().proxy.$api104
const { toClipboard } = useClipboard()

const paymentTypeMap = {
  1: {
    name: '信用卡'
  },
  2: {
    name: 'WebAtm'
  },
  3: {
    name: 'ibon'
  },
  4: {
    name: '超商 / 郵局 代收'
  },
  5: {
    name: 'ATM'
  },
  10: {
    name: 'Line Pay'
  }
}

const state = reactive({
  isLoading: false,
  isSuccess: false,
  message: '',
  successPaymentType: computed(
    () => paymentTypeMap[props.paymentType].name
  ),
  virtualAccount: '',
  dueDate: '',
  bankName: '',
  bankCode: '',
  branchName: '',
  branchCode: '',
  barcodeData: {
    storeAccount1: null,
    storeAccount2: null,
    storeAccount3: null,
    storeBarCode1: null,
    storeBarCode2: null,
    storeBarCode3: null,
    postAccount1: null,
    postAccount2: null,
    postAccount3: null,
    postBarCode1: null,
    postBarCode2: null,
    postBarCode3: null,
    receiptAmount: 0,
    dueDate: ''
  },
  isMobile: computed(() => billingStore.isMobile),
  result: computed(() => billingStore.result),
  storeIcon: import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat('/img/icon_payment_711.svg') : storeImage,
  postIcon: import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat('/img/icon_payment_post.svg') : postImage,
  botIcon: import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat('/img/icon_payment_bank.svg') : botImage,
  checkIcon: import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat('/img/icon-check-circle.svg') : checkImage,
  copyIcon: import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat('/img/icon-16-tool-icon-copy.svg') : copyImage,
  idTokenHash: computed(() => billingStore.idTokenHash),
  config: computed(() => ({
    headers: {
      '104-Pay-Hmac': paymentHash,
      'Id-Token-Hash': state.idTokenHash
    }
  })),
  isShowDueDate: getDueDate(orderInfos) ? '1' : '0',
  totalAmount: formatCurrency(billingStore.paymentTotalAmount),
  isShowToast: false,
  copyText: '已複製帳號'
})

const updatePaymentTotalAmount = (totalAmount: number) => {
  state.totalAmount = formatCurrency(totalAmount)
  billingStore.updatePaymentTotalAmount(totalAmount)
}

const getResult = (orderInfos: OrderInfo[]) => {
  const orderInfoList = getOrderInfoList(orderInfos)
  const result = {
    buId: null,
    paymentType: null,
    paymentStatus: 0,
    virtualAccount: null,
    approveCode: null,
    customerTransDate: null,
    orderIdList: null
  } as Result
  if (orderInfoList.length > 0) {
    result.buId = orderInfoList[0].buId
    result.paymentType = props.paymentType
    // 選擇完付款方式後 會回傳給 bu 資訊, 目前 paymentType 3 回 ibon虛擬帳號 , 4 回超商虛擬帳號, 5 只回 atm 虛擬帳號
    result.virtualAccount = props.paymentType === '4' ? state.barcodeData.storeAccount2 : state.virtualAccount
    result.orderIdList = orderInfoList.map(value => value.orderId)
  }
  return result
}

const updateResult = (currentResult) => {
  if (state.result.virtualAccount !== currentResult.virtualAccount) {
    billingStore.updateResult(currentResult)
    if (window.payComplete) {
      window.payComplete(currentResult)
    }
  }
}

onMounted(async () => {
  emit('update-disable-payment', true)
  state.isLoading = true
  if (props.paymentType === '3') {
    const response = await api104.get(
      '/webapis/pay/ibon',
      state.config
    )
    if (response && response.data && response.data.data) {
      state.isSuccess = true
      billingStore.updateShowPayment(false)
      const { data } = response.data
      state.virtualAccount = data.virtualAccount
      state.dueDate = data.dueDate
      updatePaymentTotalAmount(data.unpaidAmount)
      updateResult(getResult(orderInfos))
    } else if (response && response.data && response.data.message) {
      state.message = response.data.message
    }
  } else if (props.paymentType === '4') {
    const response = await api104.get(
      '/webapis/pay/barcode',
      state.config
    )
    if (response && response.data && response.data.data) {
      state.isSuccess = true
      billingStore.updateShowPayment(false)
      const { data } = response.data
      state.barcodeData = data
      state.dueDate = data.dueDate
      updatePaymentTotalAmount(data.unpaidAmount)
      updateResult(getResult(orderInfos))
    } else if (response && response.data && response.data.message) {
      state.message = response.data.message
    }
  } else if (props.paymentType === '5') {
    const response = await api104.get(
      '/webapis/pay/atm',
      state.config
    )
    if (response && response.data && response.data.data) {
      state.isSuccess = true
      billingStore.updateShowPayment(false)
      const { data } = response.data
      state.virtualAccount = data.virtualAccount
      state.dueDate = data.dueDate
      state.bankName = data.bankName
      state.bankCode = data.bankCode
      state.branchName = data.branchName
      state.branchCode = data.branchCode
      state.barcodeData = data
      updatePaymentTotalAmount(data.unpaidAmount)
      updateResult(getResult(orderInfos))
    } else if (response && response.data && response.data.message) {
      state.message = response.data.message
    }
  }
  state.isLoading = false
  emit('update-disable-payment', false)
})

const formatBase64 = (base64Data) => {
  const binary = atob(base64Data.replace(/\s/g, ''))
  const buffer = new ArrayBuffer(binary.length)
  const afterFormat = new Uint8Array(buffer)
  for (let i = 0; i < binary.length; i++) {
    afterFormat[i] = binary.charCodeAt(i)
  }
  return afterFormat
}

const isSafari = navigator.vendor && navigator.vendor.indexOf('Apple') > -1 &&
  navigator.userAgent &&
  navigator.userAgent.indexOf('CriOS') === -1 &&
  navigator.userAgent.indexOf('FxiOS') === -1

const download = (data) => {
  const type = isSafari ? 'application/octet-stream' : 'application/pdf'
  const blob = new Blob([formatBase64(data)], { type })
  const fileName = '104繳款單.pdf'
  if (navigator.msSaveOrOpenBlob) {
    navigator.msSaveOrOpenBlob(blob, fileName)
  } else if (isSafari) {
    const link = document.createElement('a')
    link.href = URL.createObjectURL(blob)
    link.download = fileName
    link.click()
    URL.revokeObjectURL(link.href)
  } else {
    window.open(URL.createObjectURL(blob), '_blank')
  }
}

const getPdf = async (type: number) => {
  state.isLoading = true
  const response = await api104.post(
    '/webapis/pdf/download',
    { type },
    state.config
  )
  if (response && response.data && response.data.data) {
    download(response.data.data)
  } else {
    state.message = '列印失敗'
  }
  state.isLoading = false
}

const doCopyText = async () => {
  try {
    await toClipboard(state.virtualAccount)
    state.copyText = '已複製帳號'
    state.isShowToast = true
  } catch (e) {
    state.copyText = '複製帳號發生錯誤: ' + e.toString()
  }
  setTimeout(() => {
    state.isShowToast = false
  }, 2000)
}

</script>

