<template>
  <div class="message-receiver">
    <h2>Line Pay 訊息接收器</h2>
    
    <div class="info-message">
      <h4>重要提示</h4>
      <p>因為 CORS 限制，本頁面可能會收到一個"空回應" (opaque response)。</p>
      <p>這樣的回應無法檢視內容，但請求已成功發送。</p>
      <p>主要依賴 postMessage 或 Broadcast Channel 來接收參數。</p>
    </div>
    
    <div v-if="messages.length > 0" class="messages-container">
      <h3>已接收到訊息 ({{ messages.length }})</h3>
      
      <div class="messages-list">
        <div v-for="(message, index) in messages" :key="index" class="message-item">
          <div class="message-header">
            <strong>訊息 #{{ index + 1 }}</strong>
            <span class="message-time">{{ new Date(message.timestamp).toLocaleString() }}</span>
          </div>
          <div class="message-origin">來源: {{ message.origin }}</div>
          <div class="message-content">
            <pre>{{ JSON.stringify(message.data, null, 2) }}</pre>
          </div>
        </div>
      </div>
      
      <button class="clear-button" @click="clearMessages">清除訊息</button>
    </div>
    
    <div v-else class="waiting-message">
      <p>等待接收 postMessage 訊息...</p>
      <p class="info-text">此頁面已設置監聽器，接收來自其他頁面的 postMessage 訊息。</p>
    </div>
  </div>
</template>

<script setup>
import { ref, onMounted, onBeforeUnmount } from 'vue'

// 存儲收到的訊息
const messages = ref([])

// 處理接收到的 postMessage 訊息
const handleMessage = (event) => {
  console.log('收到 postMessage:', event)
  console.log('訊息來源:', event.origin)
  console.log('訊息內容:', event.data)
  
  // 將訊息添加到列表中
  messages.value.unshift({
    timestamp: Date.now(),
    origin: event.origin,
    data: event.data
  })
  
  // 如果是字符串，嘗試解析 JSON
  if (typeof event.data === 'string') {
    try {
      const parsedData = JSON.parse(event.data)
      console.log('解析後的 JSON 訊息:', parsedData)
    } catch (e) {
      console.log('非 JSON 格式字符串:', event.data)
    }
  }
}

// 清除所有訊息
const clearMessages = () => {
  messages.value = []
}

// 在組件掛載時設置監聽器
onMounted(() => {
  window.addEventListener('message', handleMessage)
  console.log('postMessage 監聽器已設置')
})

// 在組件卸載前移除監聽器
onBeforeUnmount(() => {
  window.removeEventListener('message', handleMessage)
  console.log('postMessage 監聽器已移除')
})
</script>

