import { createMemoryHistory, createRouter, type RouteRecordRaw } from 'vue-router'
import Home from '@/views/Home.vue'

const routes: Array<RouteRecordRaw> = [
  {
    path: '/',
    name: 'Home',
    component: Home,
    children: [
      {
        path: 'credit-card',
        name: 'CreditCard',
        component: () => import('@/components/CreditCard.vue'),
        props: true
      },
      {
        path: 'installment',
        name: 'Installment',
        component: () => import('@/components/Installment.vue'),
        props: true
      },
      {
        path: 'atm',
        name: 'Atm',
        component: () => import('@/components/Atm.vue'),
        props: true
      },
      {
        path: 'ibon',
        name: 'Ibon',
        component: () => import('@/components/Ibon.vue'),
        props: true
      },
      {
        path: 'barcode',
        name: 'Barcode',
        component: () => import('@/components/Barcode.vue'),
        props: true
      },
      {
        path: 'credit-card/fail',
        name: 'CreditCardFail',
        component: () => import('@/components/CreditCardFail.vue'),
        props: true
      },
      {
        path: 'credit-card/success/:paymentType/:saveCardStatus',
        name: 'CreditCardSuccess',
        component: () => import('@/components/CreditCardSuccess.vue'),
        props: route => ({
          paymentType: route.params.paymentType,
          saveCardStatus: route.params.saveCardStatus
        })
      },
      {
        path: 'line-pay',
        name: 'LinePay',
        component: () => import('@/components/LinePay.vue'),
        props: true
      },
      {
        path: 'line-pay-receiver',
        name: 'LinePayReceiver',
        component: () => import('@/components/LinePayReceiver.vue'),
        props: true
      },
      {
        path: 'line-pay-message-receiver',
        name: 'LinePayMessageReceiver',
        component: () => import('@/components/LinePayMessageReceiver.vue'),
        props: true
      },
      {
        path: 'complete/:paymentType',
        name: 'Complete',
        component: () => import('@/components/Complete.vue'),
        props: route => ({
          paymentType: route.params.paymentType
        })
      }
    ]
  },
  { path: '/:NoMatch(.*)*', component: Home }
]

const router = createRouter({
  history: createMemoryHistory(import.meta.env.BASE_URL),
  routes
})
export default router
