<script setup lang="ts">
import checkImage from '@/assets/images/icon-check-circle.svg'
import { computed, reactive } from 'vue'

interface Props {
  paymentType: string
  saveCardStatus: string
}

const props = withDefaults(defineProps<Props>(), {
  paymentType: '',
  saveCardStatus: ''
})

const paymentTypeMap = {
  1: {
    name: '信用卡'
  },
  2: {
    name: 'WebAtm'
  },
  3: {
    name: 'ibon'
  },
  4: {
    name: '超商'
  },
  5: {
    name: 'ATM'
  }
}
const state = reactive({
  successPaymentType: computed(
    () => paymentTypeMap[props.paymentType].name
  ),
  npcMessage: computed(() => {
    const saveCardStatus = props.saveCardStatus
    if (saveCardStatus) {
      if (saveCardStatus === '1') {
        return '並設定為常用支付方式。'
      } else if (saveCardStatus === '3') {
        return '並重新設定為常用支付方式。'
      }
    }
    return ''
  }),
  checkIcon: import.meta.env.VITE_APP_WEB_API_DOMAIN ? import.meta.env.VITE_APP_WEB_API_DOMAIN.concat('/img/icon-check-circle.svg') : checkImage
})
</script>

<template>
  <div ref="payment-method" class="payment-method payment-message" style="position:relative">
    <div class="pay-success-row save-card-payment-message">
      <div>
        <img class="icon" :src="state.checkIcon" alt="check-circle" />
        <span class="title">您已使用</span>
        <span class="title payment-type">{{ state.successPaymentType }}</span>
        <span class="title">付款完成</span>
        <span class="title">{{ state.npcMessage ? '，' : '' }}</span>
      </div>
      <div v-if="state.npcMessage">
        <span class="title">{{ state.npcMessage }}</span>
      </div>
    </div>
  </div>
</template>
