<script setup lang="ts">
// @ is an alias to /src
import Payment from '@/components/Payment.vue'
import Notice from '@/components/Notice.vue'
import FreePayment from '@/components/FreePayment.vue'
import { useBillingStore } from '@/stores'
import { onMounted, reactive } from 'vue'
import { PaymentInfo } from '@/types'

const props = defineProps<{
  paymentInfo: PaymentInfo
}>()

const billingStore = useBillingStore()
const state = reactive({
  orderInfos: null,
  paymentHash: null,
  paymentType: null,
  paymentTotalAmount: 0
})

const isOrderInfosNotEmpty = (paymentInfo: PaymentInfo) =>
  paymentInfo &&
  paymentInfo.orderInfos &&
  paymentInfo.orderInfos.length > 0

const ConvenienceStoreAmountLargerThanMaxDisablePaymentType = ['3', '4']

const setPaymentType = (paymentInfo: PaymentInfo) => {
  if (isOrderInfosNotEmpty(paymentInfo)) {
    state.orderInfos = paymentInfo.orderInfos
    state.paymentHash = paymentInfo.paymentHash
    // 找第一筆訂單的付款方式，因為同一個商店付款方式相同
    const orderPaymentType = paymentInfo.paymentType
    const paymentTotalAmount = paymentInfo.paymentTotalAmount
    state.paymentTotalAmount = paymentTotalAmount
    if (paymentTotalAmount > 40000) {
      const usefulOrderPaymentType = orderPaymentType.split('|').filter(type => !ConvenienceStoreAmountLargerThanMaxDisablePaymentType.includes(type)).join('|')
      state.paymentType = usefulOrderPaymentType
      billingStore.updateOrderPaymentType(usefulOrderPaymentType)
    } else {
      state.paymentType = orderPaymentType
      billingStore.updateOrderPaymentType(orderPaymentType)
    }
  }
}

const setSaveCardInfo = (paymentInfo: PaymentInfo) => {
  if (paymentInfo && paymentInfo.saveCardInfo) {
    billingStore.updateSaveCardInfo(paymentInfo.saveCardInfo)
  }
}

const setInstallmentInfo = (paymentInfo: PaymentInfo) => {
  if (paymentInfo && paymentInfo.installmentInfos) {
    billingStore.updateInstallmentInfos(paymentInfo.installmentInfos)
  }
}

const getErrorMessage = (paymentInfo: PaymentInfo) => {
  return paymentInfo.message ? paymentInfo.message : ''
}

onMounted(() => {
  setPaymentType(props.paymentInfo)
  setSaveCardInfo(props.paymentInfo)
  setInstallmentInfo(props.paymentInfo)
})
</script>

<template>
  <div class="wrap">
    <template v-if="state.orderInfos && state.orderInfos.length > 0 && state.paymentTotalAmount > 0">
      <Payment
        :payment-type="state.paymentType"
        :payment-hash="state.paymentHash"
        :order-infos="state.orderInfos"
        :payment-total-amount="state.paymentTotalAmount"
      />
    </template>
    <template v-else-if="state.orderInfos && state.orderInfos.length > 0 && state.paymentTotalAmount === 0">
      <FreePayment :payment-hash="state.paymentHash" :order-infos="state.orderInfos" />
    </template>
    <template v-else>
      <div class="payment-container">
        <div ref="payment-method" class="payment-method" style="position:relative">
          <Notice :title="'無法付款'" :description="getErrorMessage(props.paymentInfo)" />
        </div>
      </div>
    </template>
  </div>
</template>
