<script setup lang="ts">
import { useBillingStore } from '@/stores'
import { PaymentOrders } from '@/types'
import { ApiResponse } from 'axios'
import { computed, getCurrentInstance, nextTick, onBeforeUnmount, onMounted, reactive, ref, watch } from 'vue'
import { useRouter } from 'vue-router'

interface Props {
  paymentOrders?: PaymentOrders,
  width?: string
}

const props = withDefaults(defineProps<Props>(), {
  paymentOrders: null,
  width: '1200px'
})

const router = useRouter()
const billingStore = useBillingStore()
const api104 = getCurrentInstance().proxy.$api104
const appRef = ref<HTMLElement | null>(null)

const logout = async (idTokenHash: string) => {
  if (idTokenHash) {
    await api104.delete('/webapis/ac/logout', {
      headers: {
        'Id-Token-Hash': idTokenHash
      }
    })
  }
}
// 閒置8小時候登出
setTimeout(() => logout(billingStore.idTokenHash), 28800000)

const state = reactive({
  paymentInfo: null,
  customWidth: computed(() => billingStore.customWidth),
  isLoading: false
})

const mapOrders = async (orderHashList: object[], installmentTermList: number[]): Promise<void> => {
  state.isLoading = true
  const response = await api104.post<ApiResponse>(
    '/webapis/order/mapping',
    { orderHashList, installmentTermList },
    {
      headers: {
        'Id-Token-Hash': billingStore.idTokenHash
      }
    }
  )
  state.isLoading = false
  if (response && response.data && response.data.success) {
    state.paymentInfo = response.data.data
  } else {
    state.paymentInfo = response.data ? response.data : {}
  }
}

watch(
  [() => props.paymentOrders, () => props.width],
  ([paymentOrders, width]) => {
    billingStore.updateWidth(width)
    billingStore.updateDefaultOpenPaymentType(paymentOrders.defaultOpenPaymentType)
    billingStore.updateDefaultAgreeSaveCard(paymentOrders.defaultAgreeSaveCard)
    billingStore.updateIdTokenHash(paymentOrders.idTokenHash)

    mapOrders(paymentOrders.orderHashList, paymentOrders.installmentTermList)
  }
)

/**
 * 檢查 localStorage 中的參數
 */
const checkLocalStorageParams = () => {
  try {
    console.log('[App] 檢查 localStorage 參數...')
    
    // 用於儲存所有找到的 localStorage 參數
    const localStorageParams = {}
    
    // 查找可能與支付相關的 LocalStorage 鍵值對
    const paymentRelatedKeys = [
      'linePayStatus',
      'lastProcessedPaymentTimestamp',
      'lastCheckedPaymentTimestamp',
      'linePayTimestamp'
    ]
    
    // 檢查所有可能與支付相關的 localStorage 鍵值
    paymentRelatedKeys.forEach(key => {
      const value = localStorage.getItem(key)
      if (value) {
        localStorageParams[key] = value
      }
    })
    
    // 如果找到任何參數，則輸出到控制台
    if (Object.keys(localStorageParams).length > 0) {
      console.log('[App] 在 localStorage 中找到支付相關參數:', localStorageParams)
    } else {
      console.log('[App] localStorage 中沒有支付相關參數')
    }
  } catch (error) {
    console.error('[App] 檢查 localStorage 參數時出錯:', error)
  }
}

/**
 * 檢查 URL 參數
 */
const checkUrlParams = () => {
  try {
    console.log('[App] 檢查 URL 參數...')
    
    // 取得目前 URL 中的所有參數
    const urlParams = new URLSearchParams(window.location.search)
    
    // 將參數轉換為對象
    const params = {}
    for (const [key, value] of urlParams.entries()) {
      params[key] = value
    }
    
    // 如果 URL 中有參數，則輸出到控制台
    if (Object.keys(params).length > 0) {
      console.log('[App] 目前 URL 中的參數:', params)
      console.log('[App] 完整 URL:', window.location.href)
    } else {
      console.log('[App] URL 中沒有參數')
    }
  } catch (error) {
    console.error('[App] 檢查 URL 參數時出錯:', error)
  }
}

/**
 * 超商確認付款畫面, 需要知道是手機還是電腦, 來顯示不同的文字描述及列印按鈕
 */
const updateIsMobile = () => {
  // 取得 ref 到的 component
  const appElement = appRef.value
  // 取得 DOMRect 的寬度, 並比較 browser 寬度, 取較小值
  const appWidth = Math.min(appElement?.getBoundingClientRect()?.width ?? window.innerWidth, window.innerWidth)

  // 依裝置 / component 寬度 / browser 寬度判斷是否為手機版
  if (/Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent) || appWidth <= 800) {
    billingStore.updateMobile(true)
  } else {
    billingStore.updateMobile(false)
  }
}

onMounted(() => {
  // 觸發 easyPayReady 事件告知外部可傳遞參數過來
  nextTick(() => {
    const easyPayReady = new CustomEvent('easyPayReady')
    document.dispatchEvent(easyPayReady)
    // 當 easyPay component 載入完成後，才做是否為手機版的判斷
    updateIsMobile()
    
    // 主動檢查 localStorage 中的參數
    checkLocalStorageParams()
    
    // 主動檢查 URL 參數
    checkUrlParams()
  })
  window.onresize = updateIsMobile
})

onBeforeUnmount(() => {
  // 因不同 BU 會有不同控制 web-component 的方式, 如不重新整理, 單純 remove web-component 時, pinia 及 router 的狀態還是會存在,
  // 會導致某些動作無法被正確觸發 (e.g 預設打開付款方式), 所以當移除 web-component 時, 就 reset 所有 pinia 參數.
  billingStore.$reset()
  router.push({ name: 'Home' })
})
</script>

<template>
  <div
    id="app"
    ref="appRef"
    :style="{ '--custom-width': state.customWidth }"
  >
    <!--原本的 active 渲染方式, 會導致 loading 圖案卡住, 所以使用 vue v-if 渲染 -->
    <loading-component v-if="state.isLoading" loader="spinner" :active="true" :is-full-page="true" />
    <router-view v-if="state.paymentInfo" :payment-info="state.paymentInfo" />
  </div>
</template>

<style lang="scss">
@use "@/assets/scss/base.scss";
</style>
