import { defineRule, type ValidationResult } from 'vee-validate'

const year = new Date().getFullYear() % 100

// 必填欄位
defineRule('required', (value: string, [message]: string): string | boolean => {
  return !!value || `${message || '此欄位為必填'}`
})

// 數字格式
defineRule('digitNumber', (value: string, [message]: string): string | boolean => {
  return !value || /^\d+$/.test(value) || `${message || '格式錯誤'}`
})

// 安全碼格式
defineRule('securityCode', (value: string, [message]: string): string | boolean => {
  return !value || /^[0-9]{3}$/.test(value) || `${message || '安全碼 格式錯誤'}`
})

// 月份格式
defineRule('month', (value: string, [message]: string): string | boolean => {
  return !value || /^(0?[1-9]|1[012])$/.test(value) || `${message || '月份 格式錯誤'}`
})

// 年度格式
defineRule('year', (value: string, [message]: string): string | boolean => {
  return !value || /^\d{2}$/.test(value) || parseInt(value) < year || `${message || '年度 格式錯誤'}`
})

// 提供 handleSubmit 在沒通過驗證時, callback 此 function, 並 focus 到第一個錯誤欄位
export const goToFirstError = (form: Element, results: Record<string, ValidationResult>): void => {
  const elements = [...form.querySelectorAll('input')]
  const resultsValue = Object.values(results)
  form.scrollIntoView()
  for (let i = 0; i < resultsValue.length; i++) {
    if (!(resultsValue[i] as ValidationResult).valid) {
      elements[i].focus()
      break
    }
  }
}
