import { commaFormat, priceFormat } from '@/plugins/formatter'
import type { OrderInfo } from '@/types'

export const formatCurrency = (amount: number): string => {
  return priceFormat(commaFormat(amount))
}

const compareDate = (a: Date, b: Date): number => {
  if (a > b) {
    return 1
  } else if (a < b) {
    return -1
  } else {
    return 0
  }
}

export const getDueDate = (orderInfos: OrderInfo[]): string => {
  if (!orderInfos) return ''
  const orderInfoArray: OrderInfo[] = (orderInfos.filter((value: OrderInfo) => value.paymentDueDate).sort((a, b) => compareDate(new Date(a.paymentDueDate), new Date(b.paymentDueDate))))
  return orderInfoArray && orderInfoArray.length > 0 ? orderInfoArray[0].paymentDueDate.slice(0, 10) : ''
}

export const getOrderInfoList = (orderInfos: OrderInfo[]): OrderInfo[] => {
  return !orderInfos ? [] : orderInfos
}
