// 加上 $ 字號
export const priceFormat = (value: string) => 'NT$ ' + value

export const commaFormat = (value: number) => {
  // 加上千分位符號
  return value
    .toString()
    .replace(/^(-?\d+?)((?:\d{3})+)(?=\.\d+$|$)/, function (
      all,
      pre,
      groupOf3Digital
    ) {
      return pre + groupOf3Digital.replace(/\d{3}/g, ',$&')
    })
}
